import {
  createContext,
  useContext,
  useRef,
  type PropsWithChildren,
} from 'react';

import { createStore } from '../../../../../core/store/store.js';
import type { TooltipState, TooltipStore } from '../types.js';
import { emptyData } from '../utils.js';

const initialState: () => TooltipState = () => ({
  pinned: false,
  inBounds: false,
  activeSeries: null,
  absoluteX: null,
  absoluteY: null,
  relativeX: null,
  relativeY: null,
  percentX: null,
  percentY: null,
  data: emptyData(),
});

export const TooltipContext = createContext<TooltipStore>({} as TooltipStore);

/**  @internal  */
export const useTooltip = () => {
  const tooltip = useContext(TooltipContext);

  if (!tooltip) {
    throw new Error('useTooltip not used within TooltipContext provider.');
  }

  return tooltip;
};

/**  @internal  */
export function TooltipProvider(
  props: PropsWithChildren<{ persistedStore?: boolean }>,
) {
  const store = useRef<TooltipStore>();
  if (props.persistedStore) {
    store.current ||= createStore<TooltipState>(initialState());
  } else {
    store.current = createStore<TooltipState>(initialState());
  }

  return (
    <TooltipContext.Provider value={store.current}>
      {props.children}
    </TooltipContext.Provider>
  );
}
